            { q: 'What counts as retrieval practice?', options: ['Only written tests', 'Any activity where pupils recall from memory: flashcards, whiteboards, verbal rounds', 'Only homework', 'Only at the end of term'], correct: 'Any activity where pupils recall from memory: flashcards, whiteboards, verbal rounds' }
